import React from 'react';

function Education({ data }) {
  if (!data) return null;

  return (
    <section id="education" className="py-12 md:py-16 bg-[#eaf2f6]">
      <div className="max-w-7xl mx-auto px-4">
        <div className="mb-8 md:mb-10">
          <p className="text-[10px] uppercase tracking-[0.4em] text-[#4a6f79] font-semibold mb-3">
            Formation
          </p>
          <h2
            className="text-3xl md:text-5xl text-[#113641] leading-tight"
            style={{ fontFamily: '"DM Serif Display", "Times New Roman", serif', fontWeight: 400 }}
          >
            Education path
          </h2>
        </div>

        <div className="relative pl-6 md:pl-10">
          <div className="absolute left-2 md:left-4 top-0 bottom-0 w-px bg-[#9ec0ca]" />

          <div className="space-y-5">
            {data.map((edu) => (
              <article key={edu.id} className="relative rounded-3xl border border-[#b7d0d8] bg-white p-5 md:p-6 shadow-[0_12px_30px_rgba(15,76,92,0.08)]">
                <span className="absolute -left-[26px] md:-left-[34px] top-6 h-3 w-3 rounded-full bg-[#0f4c5c] ring-4 ring-[#eaf2f6]" />

                <div className="flex items-start gap-4">
              {(edu.image || edu.institution === 'Chandigarh University' || edu.institution === 'Kumarkhatri Govt. College, Kushia') ? (
                    <div className="flex-shrink-0 w-14 h-14 flex items-center justify-center bg-[#eef6f8] rounded-xl overflow-hidden border border-[#d2e3e8]">
                    <img
                      src={edu.image || (edu.institution === 'Chandigarh University' ? '/chandigarh-university.png' : '/images.png')}
                      alt={edu.institution}
                      className="w-full h-full object-contain p-1"
                    />
                  </div>
              ) : edu.icon ? (
                    <div className="flex-shrink-0 w-14 h-14 flex items-center justify-center bg-[#eef6f8] rounded-xl text-2xl border border-[#d2e3e8]">
                    {edu.icon}
                  </div>
              ) : null}
              
                  <div className="flex-1 min-w-0">
                    <p className="text-[10px] uppercase tracking-[0.28em] text-[#5a808b] mb-2">{edu.period}</p>
                    <h3 className="text-lg md:text-xl font-black text-[#113641] mb-1 leading-tight">
                    {edu.institution}
                  </h3>
                    <p className="text-sm md:text-base text-[#38606b] mb-2">
                    {edu.degree}
                  </p>
                    {edu.details && <p className="text-sm text-[#507782] leading-relaxed">{edu.details}</p>}
                  </div>
                </div>
              </article>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

export default Education;
